{"filter":false,"title":"tool_b1_extras.py","tooltip":"/evaluation/tool_b1_extras.py","undoManager":{"mark":0,"position":0,"stack":[[{"start":{"row":0,"column":0},"end":{"row":260,"column":0},"action":"insert","lines":["# evaluation/tool_b1_extras.py","from __future__ import annotations","","import json","import math","from dataclasses import dataclass","from pathlib import Path","from typing import Any, Dict, List, Sequence","","import pandas as pd","","from evaluation.loader import TrialRecord","from evaluation.text_normalize import normalize_text","from evaluation.llm_labeler import LLMLabeler, LabelerConfig","","","def _load_meaning_keys(categories_path: Path) -> List[str]:","    cfg = json.loads(categories_path.read_text(encoding=\"utf-8\"))","    return [c[\"key\"] for c in cfg[\"meaning_categories\"]]","","","def _normalized_entropy_from_vector(vec: List[int]) -> float:","    \"\"\"","    vec（カテゴリ合計スコアのベクトル）から正規化エントロピーを算出（0..1）","    - total=0 の場合は 0.0","    - p_i = v_i / sum(v)","    - H = -sum p_i log(p_i)","    - H_norm = H / log(K)  (K=len(vec))","    \"\"\"","    k = len(vec)","    if k <= 1:","        return 0.0","    total = sum(vec)","    if total <= 0:","        return 0.0","","    ps = [v / total for v in vec if v > 0]","    h = -sum(p * math.log(p) for p in ps)","    h_max = math.log(k)","    return float(h / h_max) if h_max > 0 else 0.0","","","@dataclass","class ToolBExtrasOutputs:","    # sample_id × category_score_sum（+ total_score / normalized_entropy_* 等を含む）","    category_sum_df: pd.DataFrame","","    # sample_id × 指標（主指標H_no_activity + 補助指標activity_* + 参考H_all）","    entropy_df: pd.DataFrame","","    # sample_id × extra_id × category_score（横持ち）","    extra_detail_df: pd.DataFrame","","    report: Dict[str, Any]","","","def run_tool_b_meaning_scores_extras(","    trials: Sequence[TrialRecord],","    *,","    prompt_path: Path,","    categories_path: Path,","    outputs_dir: Path,","    temperature: float = 0.2,","    max_retries: int = 2,",") -> ToolBExtrasOutputs:","    \"\"\"","    ツールB1-extras（IR網羅性：意味カテゴリスコア + 正規化エントロピー）","    対象：","    - objective_card.extras（配列要素を1件ずつ評価対象として扱う）","","    出力：","    1) category_sum_df：sample_id×category_score_sum（+ total_score）","    2) entropy_df：","       - normalized_entropy_no_activity（主指標：Activity除外、K=11）","       - normalized_entropy_all（参考：全カテゴリ、K=12）","       - activity_sum / activity_mean / activity_ratio / activity_saturation（補助）","    3) extra_detail_df：sample_id×extra_id×category_score（横持ち）","","    sample_id：","    - ZIP名を sample_id として用いる（B1と同じ）","    ログ（追記式）：","    - outputs_dir/tool_b_labels.jsonl","    - outputs_dir/tool_b_errors.jsonl","    \"\"\"","    outputs_dir.mkdir(parents=True, exist_ok=True)","    out_jsonl = outputs_dir / \"tool_b_labels.jsonl\"","    err_jsonl = outputs_dir / \"tool_b_errors.jsonl\"","","    meaning_keys = _load_meaning_keys(categories_path)","","    labeler = LLMLabeler(","        LabelerConfig(","            prompt_path=prompt_path,","            categories_path=categories_path,","            temperature=temperature,","            max_retries=max_retries,","        )","    )","","    # 詳細（sample_id×extra_id×category）横持ち行","    detail_rows: List[Dict[str, Any]] = []","","    # 合計（sample_id×category）を辞書で集計","    sum_map: Dict[str, Dict[str, int]] = {}","","    for t in trials:","        sample_id = t.zip_name","        meta = dict(t.meta or {})","        meta.update({\"run_id\": t.run_id})","","        if sample_id not in sum_map:","            sum_map[sample_id] = {k: 0 for k in meaning_keys}","","        extras_raw = t.objective_card.get(\"extras\")","","        # extras が「配列」以外で来ても最低限拾えるようにする","        extras_list: List[Any]","        if extras_raw is None:","            extras_list = []","        elif isinstance(extras_raw, list):","            extras_list = extras_raw","        else:","            # 文字列1本などの場合は1要素として扱う","            extras_list = [extras_raw]","","        for idx, item in enumerate(extras_list, start=1):","            text = normalize_text(item)","            if not text:","                continue","","            extra_id = f\"extras_{idx:02d}\"","","            out = labeler.label_meaning_scores(","                sample_id=sample_id,","                text_id=extra_id,   # jsonl上の識別子","                raw_text=text,","                meta=meta,","                out_jsonl=out_jsonl,","                err_jsonl=err_jsonl,","            )","            if not out:","                continue","","            scores: Dict[str, int] = out[\"scores\"]","","            row = {\"sample_id\": sample_id, \"extra_id\": extra_id}","            for k in meaning_keys:","                v = int(scores.get(k, 0))","                row[k] = v","                sum_map[sample_id][k] += v","            detail_rows.append(row)","","    # (1) sample_id × category_score_sum（横持ち）","    sum_rows: List[Dict[str, Any]] = []","    for sample_id, d in sum_map.items():","        r = {\"sample_id\": sample_id}","        for k in meaning_keys:","            r[k] = int(d.get(k, 0))","        r[\"total_score\"] = int(sum(d.get(k, 0) for k in meaning_keys))","        sum_rows.append(r)","","    category_sum_df = pd.DataFrame(sum_rows)","","    # (2) entropy（主）+ Activity補助 + entropy（参考）","    activity_key = \"Activity\"","    keys_no_activity = [k for k in meaning_keys if k != activity_key]","","    entropy_rows: List[Dict[str, Any]] = []","    for _, row in category_sum_df.iterrows():","        sample_id = row[\"sample_id\"]","        total_score = int(row[\"total_score\"])","","        vec_no_activity = [int(row[k]) for k in keys_no_activity]","        vec_all = [int(row[k]) for k in meaning_keys]","","        h_no_activity = _normalized_entropy_from_vector(vec_no_activity)","        h_all = _normalized_entropy_from_vector(vec_all)","","        activity_sum = int(row.get(activity_key, 0))","        activity_mean = float(activity_sum / max(1, len(trials)))  # B1のノリに合わせた“参考”値","        activity_ratio = float(activity_sum / total_score) if total_score > 0 else 0.0","        activity_saturation = float(activity_sum / 15.0)  # B1踏襲（目安）","","        entropy_rows.append(","            {","                \"sample_id\": sample_id,","                \"normalized_entropy_no_activity\": float(h_no_activity),","                \"normalized_entropy_all\": float(h_all),","                \"total_score\": int(total_score),","                \"activity_sum\": int(activity_sum),","                \"activity_mean\": float(activity_mean),","                \"activity_ratio\": float(activity_ratio),","                \"activity_saturation\": float(activity_saturation),","            }","        )","","    entropy_df = pd.DataFrame(entropy_rows)","","    extra_detail_df = pd.DataFrame(detail_rows)","","    # category_sum_df に主指標を併記（B1と同じ“便利合体”）","    if not category_sum_df.empty and not entropy_df.empty:","        category_sum_df = category_sum_df.merge(","            entropy_df[","                [","                    \"sample_id\",","                    \"normalized_entropy_no_activity\",","                    \"normalized_entropy_all\",","                    \"activity_sum\",","                    \"activity_mean\",","                    \"activity_ratio\",","                    \"activity_saturation\",","                ]","            ],","            on=\"sample_id\",","            how=\"left\",","        )","","    report = {","        \"tool\": \"tool_b1_extras_coverage\",","        \"sample_id_policy\": \"zip_name\",","        \"target\": \"objective_card.extras (each item)\",","        \"meaning_categories\": meaning_keys,","        \"score_scale\": \"0..3 (0 none, 3 strong)\",","        \"metrics\": {","            \"primary\": \"normalized_entropy_no_activity (K=11, Activity excluded)\",","            \"reference\": \"normalized_entropy_all (K=12)\",","            \"aux\": [","                \"activity_sum\",","                \"activity_mean\",","                \"activity_ratio (= activity_sum / total_score)\",","                \"activity_saturation (= activity_sum / 15)\",","            ],","            \"entropy_definition\": \"H_norm = (-sum p_i log p_i) / log(K), p_i = s_i / sum(s)\",","            \"entropy_range\": \"0..1 (0 concentrated, 1 uniform)\",","        },","        \"llm\": {","            \"model\": \"MODEL_NAME from chains.py\",","            \"prompt\": str(prompt_path),","            \"categories\": str(categories_path),","            \"temperature\": float(temperature),","            \"max_retries\": int(max_retries),","        },","        \"outputs\": {","            \"labels_jsonl\": str(out_jsonl),","            \"errors_jsonl\": str(err_jsonl),","        },","        \"notes\": [","            \"category_sum_df: sample_id×カテゴリ合計（+ total_score + 指標列）\",","            \"entropy_df: sample_id×指標（主/参考/補助）\",","            \"extra_detail_df: sample_id×extra_id×カテゴリスコア（横持ち）\",","        ],","    }","","    return ToolBExtrasOutputs(","        category_sum_df=category_sum_df,","        entropy_df=entropy_df,","        extra_detail_df=extra_detail_df,","        report=report,","    )",""],"id":1}]]},"ace":{"folds":[],"scrolltop":0,"scrollleft":0,"selection":{"start":{"row":260,"column":0},"end":{"row":260,"column":0},"isBackwards":false},"options":{"guessTabSize":true,"useWrapMode":false,"wrapToView":true},"firstLineState":0},"timestamp":1769745304236,"hash":"fceb1e4f0404ed5282b9f3ca012a39db637179a1"}